import React from 'react';
import Topnav from '../components/Topnav';
import Footer from '../components/Footer';
import Top_image from "../assets/top_banner.png";
import background from '../assets/background.png';
import AboutData from '../assets/About.json';

function About() {
  return (
    <>
      <Topnav />

      {/* Header Section */}
      <div
        className="flex flex-col justify-end items-center bg-cover bg-center relative h-96"
        style={{ backgroundImage: `url(${background})` }}
      >
        <div className="text-center mt-10 z-20">
          <p className="text-4xl font-bold text-gray-900 mb-2">About Me</p>
          <p className="text-2xl text-gray-700">GemAnaIyzer</p>
        </div>
        <div className="absolute top-28 w-6/12 md:w-4/12">
          <img src={Top_image} alt="Gem" className="h-64 w-full rounded-2xl shadow-xl" />
        </div>
      </div>

      {/* Content Section */}
      <div className="max-w-6xl mx-auto px-6 md:px-12 lg:px-20 py-10 space-y-6">
        <p className="text-gray-800 text-justify">{AboutData.section.paragraph1}</p>
        <p className="text-gray-800 text-justify">{AboutData.section.paragraph2}</p>
        <p className="text-gray-800 text-justify">{AboutData.section.paragraph3}</p>
        <p className="text-gray-800 text-justify">{AboutData.section.paragraph4}</p>
      </div>

      <Footer />
    </>
  );
}

export default About;
